331→            findPost(postId, blogId)?.let {
332→                readerPostCardActionsHandler.onAction(
333→                    it,
334→                    type,
335→                    isBookmarkList = false,
336→                    source = ReaderTracker.SOURCE_DISCOVER
337→                )
338→            }
339→        }
340→    }
