506→    override fun onCleared() {
507→        super.onCleared()
508→        readerDiscoverDataProvider.stop()
509→        readerPostCardActionsHandler.onCleared()
510→        readerDiscoverDataProvider.communicationChannel.removeObserver(communicationChannelObserver)
511→    }
