304→        fun getSelectedInterests(): List<ReaderTag> {
305→            return if (this is ContentUiState) {
306→                interests.filter {
307→                    getCheckedInterestsUiState().map { checkedInterestUiState ->
308→                        checkedInterestUiState.slug
309→                    }.contains(it.tagSlug)
310→                }
311→            } else {
312→                emptyList()
313→            }
314→        }
