230→    private fun getUpdatedInterestsUiState(index: Int, isChecked: Boolean): List<TagUiState> {
231→        val currentUiState = uiState.value as ContentUiState
232→        val newInterestsUiState = currentUiState.interestsUiState.toMutableList()
